            // Messages are reported only on the first invocation; a quiet reporter
            // is
            // used for subsequent invocations.
            String prefixDecl = e.getAttribute("prefix");
            EPUBLocation loc = location();
            metaVocabs = VocabUtil.parsePrefixDeclaration(prefixDecl, RESERVED_META_VOCABS, KNOWN_META_VOCAB_URIS, DEFAULT_VOCAB_URIS, report, loc);
            itemVocabs = VocabUtil.parsePrefixDeclaration(prefixDecl, RESERVED_ITEM_VOCABS, KNOWN_ITEM_VOCAB_URIS, DEFAULT_VOCAB_URIS, QuietReport.INSTANCE, loc);
            itemrefVocabs = VocabUtil.parsePrefixDeclaration(prefixDecl, RESERVED_ITEMREF_VOCABS, KNOWN_ITEMREF_VOCAB_URIS, DEFAULT_VOCAB_URIS, QuietReport.INSTANCE, loc);
            linkrelVocabs = VocabUtil.parsePrefixDeclaration(prefixDecl, RESERVED_LINKREL_VOCABS, KNOWN_LINKREL_VOCAB_URIS, DEFAULT_VOCAB_URIS, QuietReport.INSTANCE, loc);
            linkVocabs = VocabUtil.parsePrefixDeclaration(prefixDecl, RESERVED_LINK_VOCABS, KNOWN_LINK_VOCAB_URIS, DEFAULT_VOCAB_URIS, QuietReport.INSTANCE, loc);
        } else if (name.equals("metadata")) {
            metadataBuilders.addFirst(MetadataSet.builder());
            linkedResourcesBuilders.addFirst(LinkedResources.builder());
        } else if (name.equals("link")) {
            processLink();
        } else if (name.equals("item")) {
            String id = e.getAttribute("id");
            OPFItem.Builder itemBuilder = itemBuilders.get(id);
            if (itemBuilder != null) {
                processItemProperties(itemBuilder, e.getAttribute("properties"), e.getAttribute("media-type"));
            }
        } else if (name.equals("itemref")) {
