            requiredProperties.add(ITEM_PROPERTIES.SCRIPTED);
        } else if (name.equals("link")) {
            processLink();
        } else if (name.equals("audio")) {
            startMediaElement();
        } else if (name.equals("video")) {
            processVideo();
            startMediaElement();
        } else if (name.equals("figure")) {
            processFigure();
        } else if (name.equals("table")) {
            processTable();
        } else if (name.equals("track")) {
            startTrack();
