            }
        }
    } catch (IOException e) {
        report.message(MessageId.PKG_008, EPUBLocation.of(context), e.getMessage());
    } finally {
        try {
            if (epubIn != null) {
                epubIn.close();
            }
        } catch (IOException ignored) {
        }
    }
